import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';

const API = 'http://localhost:8000';

export default function FolderPage() {
  const router = useRouter();
  const { id } = router.query;
  const [folder, setFolder] = useState(null);
  const [guides, setGuides] = useState([]);

  function getToken() {
    return localStorage.getItem('authToken');
  }

  function headers() {
    return { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() };
  }

  useEffect(() => {
    if (!getToken()) { router.push('/'); return; }
    if (id) loadData();
  }, [id]);

  async function loadData() {
    try {
      const [foldersResp, guidesResp] = await Promise.all([
        fetch(API + '/folders', { headers: headers() }),
        fetch(API + '/guides?folder_id=' + id, { headers: headers() })
      ]);
      const foldersData = await foldersResp.json();
      const guidesData = await guidesResp.json();
      const currentFolder = (foldersData.folders || []).find(f => f.id === id);
      setFolder(currentFolder || { name: 'Unknown Folder' });
      setGuides(guidesData.guides || []);
    } catch (e) {
      console.error('Failed to load data', e);
    }
  }

  async function deleteGuide(guideId, e) {
    e.stopPropagation();
    if (!confirm('Delete this study guide?')) return;
    try {
      await fetch(API + '/guides/' + guideId, { method: 'DELETE', headers: headers() });
      setGuides(guides.filter(g => g.id !== guideId));
    } catch (e) {
      console.error('Failed to delete', e);
    }
  }

  async function deleteFolder() {
    if (!confirm('Delete this folder and all its guides?')) return;
    try {
      await fetch(API + '/folders/' + id, { method: 'DELETE', headers: headers() });
      router.push('/dashboard');
    } catch (e) {
      console.error('Failed to delete folder', e);
    }
  }

  function formatDate(dateStr) {
    const d = new Date(dateStr);
    return d.toLocaleDateString() + ' ' + d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }

  if (!folder) return <div className="container" style={{ marginTop: 40 }}>Loading...</div>;

  return (
    <div>
      <div className="navbar">
        <h1>AutoStudyAI</h1>
        <div>
          <a href="#" onClick={e => { e.preventDefault(); router.push('/dashboard'); }}>Dashboard</a>
          <button onClick={() => { localStorage.removeItem('authToken'); router.push('/'); }}>Logout</button>
        </div>
      </div>

      <div className="container">
        <div className="section-header" style={{ marginTop: 20 }}>
          <h2>{folder.name}</h2>
          <button className="btn btn-red" style={{ fontSize: '0.85em', padding: '6px 14px' }} onClick={deleteFolder}>
            Delete Folder
          </button>
        </div>

        <p style={{ color: '#777', marginBottom: 16 }}>{guides.length} study guides</p>

        {guides.length === 0 ? (
          <div className="empty-state">
            No study guides in this folder yet.
            <br />Use the Chrome extension to capture content and save it here.
          </div>
        ) : (
          guides.map(guide => (
            <div key={guide.id} className="card" onClick={() => router.push('/guide/' + guide.id)}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <h3>{guide.title}</h3>
                  <p>
                    {guide.source_url && <span>From: {guide.source_url.substring(0, 50)}...</span>}
                    {' '}
                    <span className="timestamp">{formatDate(guide.created_at)}</span>
                  </p>
                </div>
                <button
                  className="btn btn-red"
                  style={{ fontSize: '0.8em', padding: '4px 10px' }}
                  onClick={e => deleteGuide(guide.id, e)}
                >
                  Delete
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
